var user_id = parseInt(msg.req.query.user_id) || 1;

msg.topic = `
  SELECT c1.prise_id, c1.nom_appareil, c1.tension, c1.courant,
         c1.puissance, c1.energie_kwh, c1.cout_fcfa, c1.timestamp
  FROM consommation c1
  INNER JOIN (
    SELECT prise_id, MAX(timestamp) as last_ts
    FROM consommation
    WHERE user_id = ${user_id}
    GROUP BY prise_id
  ) latest ON c1.prise_id = latest.prise_id
          AND c1.timestamp = latest.last_ts
  WHERE c1.user_id = ${user_id}
  ORDER BY c1.prise_id
`;

msg._user_id = user_id;
return msg;

// Formate la réponse JSON propre
var result = {
    status: 'success',
    user_id: msg.user_id || 'user01',
    count: msg.payload.length,
    prises: msg.payload,
    timestamp: new Date().toISOString()
};

msg.payload = result;
msg.headers = { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' };
return msg;

var user_id  = parseInt(msg.req.query.user_id) || 1;
var prise_id = msg.req.query.prise_id || null;
var heures   = parseInt(msg.req.query.heures) || 24;

var where = `WHERE user_id = ${user_id}
  AND timestamp >= DATE_SUB(NOW(), INTERVAL ${heures} HOUR)`;

if (prise_id) {
    where += ` AND prise_id = '${prise_id}'`;
}

msg.topic = `
  SELECT prise_id, nom_appareil, tension, courant,
         puissance, energie_kwh, cout_fcfa, timestamp
  FROM consommation
  ${where}
  ORDER BY timestamp ASC
  LIMIT 500
`;

msg._user_id  = user_id;
msg._prise_id = prise_id;
msg._heures   = heures;
return msg;

var data = msg.payload;

var puissance_max = 0;
var cout_total    = 0;
var energie_max   = 0;

data.forEach(function(row) {
    if ((row.puissance   || 0) > puissance_max) puissance_max = row.puissance;
    if ((row.cout_fcfa   || 0) > cout_total)    cout_total    = row.cout_fcfa;
    if ((row.energie_kwh || 0) > energie_max)   energie_max   = row.energie_kwh;
});

var cout_mensuel_estime = Math.round(energie_max * 100 * 30);

var result = {
    status: 'success',
    user_id:  msg._user_id,
    prise_id: msg._prise_id || 'toutes',
    periode:  msg._heures + 'h',
    stats: {
        nb_mesures:          data.length,
        puissance_max_w:     Math.round(puissance_max),
        energie_kwh:         energie_max.toFixed(3),
        cout_fcfa:           Math.round(cout_total),
        cout_mensuel_estime: cout_mensuel_estime
    },
    mesures: data
};

msg.payload = result;
msg.headers = {
    'Content-Type': 'application/json',
    'Access-Control-Allow-Origin': '*'
};
return msg;

// Body attendu: { user_id, prise_id, commande }
// Ex: { "user_id": "user01", "prise_id": "clim_salon", "commande": "OFF" }
var body = msg.payload;

var user_id  = body.user_id  || null;
var prise_id = body.prise_id || null;
var commande = body.commande || null;

// Validation
if (!user_id || !prise_id || !commande) {
    msg.payload = { status: 'error', message: 'Champs requis: user_id, prise_id, commande' };
    msg.statusCode = 400;
    node.status({ fill: 'red', shape: 'ring', text: 'Commande invalide' });
    return [null, msg];
}

if (commande !== 'ON' && commande !== 'OFF') {
    msg.payload = { status: 'error', message: 'commande doit être ON ou OFF' };
    msg.statusCode = 400;
    return [null, msg];
}

// Topic MQTT de commande: senwatt/{user_id}/{prise_id}/cmd
var topic = `senwatt/${user_id}/${prise_id}/cmd`;

// Payload MQTT
var mqtt_payload = JSON.stringify({
    commande: commande,
    user_id:  user_id,
    prise_id: prise_id,
    timestamp: new Date().toISOString()
});

// Stocke les infos pour la réponse
msg._user_id  = user_id;
msg._prise_id = prise_id;
msg._commande = commande;
msg._topic    = topic;

// Prépare message MQTT
msg.topic   = topic;
msg.payload = mqtt_payload;
msg.qos     = 1;
msg.retain  = false;

node.status({ fill: 'green', shape: 'dot', text: commande + ' → ' + topic });
return [msg, null];

var reponse = {
    status:   'success',
    message:  'Commande envoyée avec succès',
    user_id:  msg._user_id,
    prise_id: msg._prise_id,
    commande: msg._commande,
    topic:    msg._topic,
    timestamp: new Date().toISOString()
};

msg.payload    = reponse;
msg.statusCode = 200;
msg.headers    = { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' };
return msg;

var user_id  = parseInt(msg.req.query.user_id) || 1;
var prise_id = msg.req.query.prise_id || null;

var where = `WHERE user_id = ${user_id}`;
if (prise_id) {
    where += ` AND prise_id = '${prise_id}'`;
}

msg.topic = `
  SELECT id, prise_id, type_alerte, message, timestamp
  FROM alertes
  ${where}
  ORDER BY timestamp DESC
  LIMIT 20
`;
msg._user_id = user_id;
return msg;

var result = {
    status: 'success',
    user_id: msg.user_id,
    nb_alertes: msg.payload.length,
    alertes: msg.payload
};
msg.payload = result;
msg.headers = { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' };
return msg;
